+        .mixer-icon { width: 14px; height: 14px; display: grid; grid-template-columns: 1fr 1fr; gap: 2px; flex-shrink: 0; }
+        .mixer-icon div { background: rgba(255,255,255,0.7); border-radius: 1px; }
+
+        /* ── CONTENT ── */
