+
+        /* 섹션 헤더 */
+        .sec-block { margin-bottom: 32px; }
+        .sec-header { display: flex; align-items: center; gap: 12px; margin-bottom: 14px; }
+        .sec-badge { font-size: 12px; font-weight: 800; color: white; padding: 4px 12px; border-radius: 6px; flex-shrink: 0; }
+        .sec-badge.engine { background: var(--blue-main); }
+        .sec-badge.pdf    { background: var(--green-main); }
+        .sec-title { font-size: 15px; font-weight: 800; color: #1e293b; }
