+        .sec-more  { font-size: 12px; font-weight: 700; cursor: pointer; flex-shrink: 0; transition: opacity 0.15s; }
+        .sec-more:hover { opacity: 0.7; }
+        .sec-more.blue  { color: var(--blue-main); }
+        .sec-more.green { color: var(--green-main); }
+        .sec-divider { border: none; border-top: 2px dashed #e2e8f0; margin: 32px 0; }
+
+        /* 카드 그리드 */
+        .card-grid { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 12px; }
+
+        /* 카드 */
+        .exam-card { background: white; border: 1px solid #f1f5f9; border-radius: 14px; overflow: hidden; display: flex; flex-direction: column; transition: 0.2s; }
+        .exam-card:hover { transform: translateY(-2px); box-shadow: 0 8px 24px rgba(0,0,0,0.06); border-color: #e2e8f0; }
+        .card-top { height: 3px; background: var(--blue-main); }
+        .card-top.green { background: var(--green-main); }
+        .card-body { padding: 16px; flex: 1; }
+        .card-grade-label { font-size: 10px; font-weight: 800; color: #94a3b8; letter-spacing: 0.5px; text-transform: uppercase; margin-bottom: 4px; }
+        .card-main-title { font-size: 15px; font-weight: 800; line-height: 1.4; margin-bottom: 11px; color: #1e293b; letter-spacing: -0.3px; }
+        .badge-row { display: flex; gap: 5px; flex-wrap: wrap; }
+        .badge { font-size: 10px; font-weight: 700; padding: 3px 7px; border-radius: 4px; }
+        .badge.blue  { background: var(--blue-pale); color: #1e40af; }
