+        .badge.gray  { background: #f1f5f9; color: #64748b; }
+
+        .card-actions { border-top: 1px solid #f1f5f9; display: flex; }
+        .action-btn { flex: 1; padding: 10px 0; text-align: center; font-size: 11px; font-weight: 700; color: #64748b; cursor: pointer; transition: 0.15s; }
+        .action-btn + .action-btn { border-left: 1px solid #f1f5f9; }
+        .action-btn:hover { background: #f8fafc; color: #1e293b; }
+        .action-btn.sole { flex: unset; width: 100%; color: var(--green-main); font-size: 12px; }
+
+        /* 연도 그룹 (전체 목록용) */
+        .yr-group { margin-bottom: 28px; }
+        .yr-group-header { display: flex; align-items: center; gap: 10px; margin-bottom: 12px; }
+        .yr-group-badge { font-size: 12px; font-weight: 800; color: white; padding: 3px 12px; border-radius: 20px; background: #334155; flex-shrink: 0; }
+        .yr-group-badge.latest { background: var(--blue-main); }
+        .yr-group-line  { flex: 1; height: 0.5px; background: #e2e8f0; }
+        .yr-group-count { font-size: 11px; color: #94a3b8; font-weight: 600; }
+        .list-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 16px; padding-top: 4px; }
+        .list-title { font-size: 15px; font-weight: 800; color: #1e293b; }
+        .list-meta  { font-size: 12px; color: #94a3b8; font-weight: 600; }
+        #full-grid { display: block; }
+        .empty-msg { grid-column: 1/-1; text-align: center; padding: 60px; color: #94a3b8; font-size: 14px; }
+
+        /* ── QPP 모달 ── */
+        .modal-overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.45); z-index: 2000; align-items: center; justify-content: center; }
+        .modal-overlay.open { display: flex; }
+        .modal-box { background: white; border-radius: 20px; padding: 36px 40px; width: 360px; box-shadow: 0 20px 60px rgba(0,0,0,0.18); text-align: center; }
+        .modal-title { font-size: 18px; font-weight: 800; color: #1e293b; margin-bottom: 6px; }
+        .modal-sub { font-size: 13px; color: #94a3b8; margin-bottom: 28px; }
+        .qpp-btns { display: flex; gap: 14px; justify-content: center; margin-bottom: 20px; }
+        .qpp-opt { flex: 1; padding: 20px 0; border: 2px solid #e2e8f0; border-radius: 14px; cursor: pointer; transition: 0.18s; font-size: 28px; font-weight: 800; color: #475569; background: #f8fafc; }
+        .qpp-opt:hover { border-color: var(--blue-main); background: #eff6ff; color: var(--blue-main); }
+        .qpp-opt span { display: block; font-size: 11px; font-weight: 600; color: #94a3b8; margin-top: 4px; }
+        .modal-cancel { font-size: 13px; color: #94a3b8; cursor: pointer; border: none; background: none; padding: 4px 12px; }
+        .modal-cancel:hover { color: #475569; }
+    </style>
+</head>
+<body>
+
+<div class="modal-overlay" id="qppModal">
+    <div class="modal-box">
+        <div class="modal-title">시험지 출력 형식</div>
+        <div class="modal-sub">한 페이지에 몇 문항을 배치할까요?</div>
+        <div class="qpp-btns">
+            <div class="qpp-opt" onclick="confirmQpp(4)">4<span>2 × 2 배열</span></div>
+            <div class="qpp-opt" onclick="confirmQpp(6)">6<span>2 × 3 배열</span></div>
+        </div>
+        <button class="modal-cancel" onclick="closeModal()">취소</button>
+    </div>
+</div>
+
+<header>
+    <div class="top-nav">
+        <div class="logo" onclick="resetView()">
+            <div class="logo-mark"><div></div><div></div><div></div><div></div></div>
+            <span class="logo-name"><em>JS</em>아카이브</span>
+        </div>
+        <nav class="grade-nav" id="gradeBar">
+            <span class="gtab" data-grade="고3">고3</span>
+            <span class="gtab" data-grade="고2">고2</span>
+            <span class="gtab" data-grade="고1">고1</span>
+            <span class="gtab" data-grade="중3">중3</span>
+            <span class="gtab" data-grade="중2">중2</span>
+            <span class="gtab active" data-grade="">전체</span>
+        </nav>
+        <span class="nav-count" id="navCount">시험지 0개</span>
+    </div>
+</header>
+
+<div class="hero">
+    <div class="hero-grid-bg"></div>
+    <div class="hero-deco" aria-hidden="true">
+        <div>∫ f(x) dx</div>
+        <div>lim<sub>n→∞</sub> aₙ</div>
+        <div>∑ aₙ = S</div>
+    </div>
+    <div class="hero-inner">
+        <div class="hero-left">
+            <div class="hero-tag"><div class="tag-dot"></div><span>수학 기출 아카이브</span></div>
+            <div class="hero-title">학교별 기출 & 변형<br><em>통합 출제 시스템</em></div>
+            <div class="hero-desc">시험지 · 해설지 · 정답표를 한 번에<br>엔진 렌더링 + PDF 기출 통합 관리</div>
+        </div>
+        <div class="stat-pills">
+            <div class="stat-pill"><div class="stat-n" id="stat-total">0</div><div class="stat-l">총 시험지</div></div>
+            <div class="stat-pill"><div class="stat-n" id="stat-grades">0</div><div class="stat-l">대상 학년</div></div>
+            <div class="stat-pill"><div class="stat-n" id="stat-pdf">0</div><div class="stat-l">PDF 기출</div></div>
+        </div>
+    </div>
+</div>
+
+<div class="filter-band">
+    <div class="filter-inner">
+        <div class="fb-search">
+            <i class="fa-solid fa-magnifying-glass fb-search-icon"></i>
+            <input type="text" id="searchInput" placeholder="학교명, 과목으로 검색…">
+        </div>
+        <div class="fb-divider"></div>
+        <div class="fb-sel-group">
+            <span class="fb-label">연도</span>
+            <select class="fb-sel" id="yearFilter">
+                <option value="">전체</option>
+            </select>
+        </div>
+        <div class="fb-sel-group">
+            <span class="fb-label">시험</span>
+            <select class="fb-sel" id="examTypeFilter">
+                <option value="">전체</option>
+                <option value="1학기중간">1학기 중간</option>
+                <option value="1학기기말">1학기 기말</option>
+                <option value="2학기중간">2학기 중간</option>
+                <option value="2학기기말">2학기 기말</option>
+            </select>
+        </div>
+        <div class="fb-divider"></div>
+        <button class="fb-mixer" onclick="location.href='mixer.html'">
+            <div class="mixer-icon"><div></div><div></div><div></div><div></div></div>
+            믹서 출제
+        </button>
+    </div>
+</div>
+
+<div class="content-wrap">
+    <div id="featured-section"></div>
+
+    <div id="full-section" style="display:none;">
+        <div class="list-header">
+            <span class="list-title" id="listTitle">전체 자료</span>
+            <span class="list-meta" id="listMeta"></span>
+        </div>
+        <div id="full-grid"></div>
+    </div>
+</div>
+
+<script>
+/* ── 상태 ── */
+let engineDB  = { exams: [] };
+let archiveDB = { files: [] };
+let selectedGrade = '';
+let _filterType   = '';   // 'engine' | 'pdf' | ''
+
+const FEATURED_GRADES = ['중2', '중3', '고1', '고2'];
+
+/* ── 초기화 ── */
+async function init() {
+    // 엔진 DB
+    await new Promise(res => {
+        const s = document.createElement('script');
+        s.src = 'db.js?v=' + Date.now();
+        s.onload = () => { engineDB = window.mainDB || window.db || { exams: [] }; res(); };
+        s.onerror = () => res();
+        document.body.appendChild(s);
+    });
+
+    // PDF 아카이브
+    try {
+        const r = await fetch('./data/catalog.json?v=' + Date.now());
+        if (r.ok) archiveDB = await r.json();
+    } catch (e) {}
+
+    updateStats();
+    populateYearFilter();
+    initGradeBar();
+    renderFeatured();
+
+    document.getElementById('searchInput').addEventListener('input', onFilterChange);
+    document.getElementById('yearFilter').addEventListener('change', onFilterChange);
+    document.getElementById('examTypeFilter').addEventListener('change', onFilterChange);
+}
+
+/* ── 통계 ── */
+function updateStats() {
+    const ve = engineDB.exams.filter(e => e.type !== 'hidden');
+    const af = archiveDB.files || [];
+    const total = ve.length + af.length;
+
+    document.getElementById('stat-total').innerText  = total;
+    document.getElementById('stat-grades').innerText =
+        new Set([...ve.map(e => e.grade), ...af.map(f => f.grade)].filter(Boolean)).size;
+    document.getElementById('stat-pdf').innerText    = af.length;
+    document.getElementById('navCount').innerText    = `시험지 ${total}개`;
+}
+
+/* ── 연도 필터 옵션 자동 생성 ── */
+function populateYearFilter() {
+    const years = new Set([
+        ...engineDB.exams.map(e => e.year),
+        ...(archiveDB.files || []).map(f => f.year)
+    ].filter(Boolean));
+
+    const sel = document.getElementById('yearFilter');
+    [...years].sort((a, b) => b - a).forEach(y => {
+        const opt = document.createElement('option');
+        opt.value = y; opt.textContent = y;
+        sel.appendChild(opt);
+    });
+}
+
+/* ── 학년 탭 ── */
+function initGradeBar() {
+    document.querySelectorAll('.gtab').forEach(tab => {
+        tab.onclick = () => {
+            document.querySelectorAll('.gtab').forEach(t => t.classList.remove('active'));
+            tab.classList.add('active');
+            selectedGrade = tab.dataset.grade;
+            onFilterChange();
+        };
+    });
+}
+
+/* ── 필터 변경 핸들러 ── */
+function onFilterChange() {
+    _filterType = '';  // 드롭다운/검색 건드리면 타입 필터 해제
+    const keyword  = document.getElementById('searchInput').value.trim();
+    const year     = document.getElementById('yearFilter').value;
+    const examType = document.getElementById('examTypeFilter').value;
+    const hasFilter = keyword || year || examType || selectedGrade || _filterType;
+
+    if (hasFilter) {
+        document.getElementById('featured-section').style.display = 'none';
+        document.getElementById('full-section').style.display = 'block';
+        renderFullList();
+    } else {
+        document.getElementById('featured-section').style.display = 'block';
+        document.getElementById('full-section').style.display = 'none';
+        renderFeatured();
+    }
+}
+
+/* ── 피처드: 엔진/PDF 2원화 렌더 ── */
+function renderFeatured() {
+    const section = document.getElementById('featured-section');
+    section.innerHTML = '';
+
+    const allEngine  = engineDB.exams.filter(e => e.type !== 'hidden');
+    const allArchive = archiveDB.files || [];
+
+    // 엔진기출 섹션 — 학년별 최신 1개
+    const engineCards = FEATURED_GRADES.map(grade => {
+        const found = allEngine
+            .filter(e => e.grade === grade)
+            .sort((a, b) => (b.year || 0) - (a.year || 0))[0];
+        return found ? { ...found, _source: 'engine' } : null;
+    }).filter(Boolean);
+
+    if (engineCards.length > 0) {
+        const engineBlock = document.createElement('div');
+        engineBlock.className = 'sec-block';
+        engineBlock.innerHTML = `
+            <div class="sec-header">
+                <span class="sec-badge engine">엔진기출</span>
+                <span class="sec-title">학교별 기출 문제</span>
+                <div class="sec-line"></div>
+                <span class="sec-count">${allEngine.length}개</span>
+                <span class="sec-more blue" onclick="showType('engine')">전체 보기 →</span>
+            </div>
+            <div class="card-grid" id="engine-grid"></div>`;
+        section.appendChild(engineBlock);
+        const grid = engineBlock.querySelector('#engine-grid');
+        engineCards.forEach(ex => grid.appendChild(buildCard(ex)));
+    }
+
+    // PDF기출 섹션 — 학년별 최신 1개
+    const pdfCards = FEATURED_GRADES.map(grade => {
+        const found = (allArchive)
+            .filter(f => f.grade === grade)
+            .sort((a, b) => (b.year || 0) - (a.year || 0))[0];
+        return found ? { ...found, _source: 'archive' } : null;
+    }).filter(Boolean);
+
+    if (pdfCards.length > 0) {
+        const divider = document.createElement('hr');
+        divider.className = 'sec-divider';
+        section.appendChild(divider);
+
+        const pdfBlock = document.createElement('div');
+        pdfBlock.className = 'sec-block';
+        pdfBlock.innerHTML = `
+            <div class="sec-header">
+                <span class="sec-badge pdf">PDF기출</span>
+                <span class="sec-title">원본 시험지 아카이브</span>
+                <div class="sec-line"></div>
+                <span class="sec-count">${allArchive.length}개</span>
+                <span class="sec-more green" onclick="showType('pdf')">전체 보기 →</span>
+            </div>
+            <div class="card-grid" id="pdf-grid"></div>`;
+        section.appendChild(pdfBlock);
+        const grid = pdfBlock.querySelector('#pdf-grid');
+        pdfCards.forEach(ex => grid.appendChild(buildCard(ex)));
+    }
+}
+
+/* ── 전체/필터 목록 렌더 (연도별 그룹핑) ── */
+function renderFullList() {
+    const keyword  = document.getElementById('searchInput').value.toLowerCase().trim();
+    const year     = document.getElementById('yearFilter').value;
+    const examType = document.getElementById('examTypeFilter').value;
+    const container = document.getElementById('full-grid');
+    container.innerHTML = '';
+
+    const engineItems = (_filterType === 'pdf') ? [] : engineDB.exams.filter(ex => {
+        if (ex.type === 'hidden') return false;
+        const matchK = !keyword || `${ex.school} ${ex.subject}`.toLowerCase().includes(keyword);
+        const matchG = !selectedGrade || ex.grade === selectedGrade;
+        const matchY = !year || String(ex.year) === String(year);
+        const typeStr = ex.semester && ex.examType
+            ? `${ex.semester}학기${ex.examType === 'mid' ? '중간' : '기말'}` : '';
+        const matchT = !examType || typeStr === examType;
+        return matchK && matchG && matchY && matchT;
+    }).map(ex => ({ ...ex, _source: 'engine' }));
+
+    const archiveItems = (_filterType === 'engine') ? [] : (archiveDB.files || []).filter(f => {
+        const matchK = !keyword || `${f.school} ${f.subject} ${f.year}`.toLowerCase().includes(keyword);
+        const matchG = !selectedGrade || f.grade === selectedGrade;
+        const matchY = !year || String(f.year) === String(year);
+        const matchT = !examType || f.exam === examType;
+        return matchK && matchG && matchY && matchT;
+    }).map(f => ({ ...f, _source: 'archive' }));
+
+    const all = [...engineItems, ...archiveItems].sort((a, b) => (b.year || 0) - (a.year || 0));
+
+    // 타이틀 / 메타
+    const typeText  = _filterType === 'engine' ? ' · 엔진기출' : _filterType === 'pdf' ? ' · PDF기출' : '';
+    const gradeText = selectedGrade ? ` · ${selectedGrade}` : '';
+    const yearText  = year ? ` · ${year}년` : '';
+    document.getElementById('listTitle').innerText = `전체 자료${typeText}${gradeText}${yearText}`;
+    document.getElementById('listMeta').innerText  = `${all.length}개 · 최신순`;
+
+    if (all.length === 0) {
+        container.innerHTML = '<div class="empty-msg">일치하는 자료가 없습니다.</div>';
+        return;
+    }
+
+    // 연도별 그룹핑
+    const grouped = {};
+    all.forEach(ex => {
+        const y = ex.year || '연도미상';
+        if (!grouped[y]) grouped[y] = [];
+        grouped[y].push(ex);
+    });
+
+    const sortedYears = Object.keys(grouped).sort((a, b) => b - a);
+    const latestYear  = sortedYears[0];
+
+    sortedYears.forEach(y => {
+        const items = grouped[y];
+        const group = document.createElement('div');
+        group.className = 'yr-group';
+        group.innerHTML = `
+            <div class="yr-group-header">
+                <span class="yr-group-badge ${y === latestYear ? 'latest' : ''}">${y}</span>
+                <div class="yr-group-line"></div>
+                <span class="yr-group-count">${items.length}개</span>
+            </div>
+            <div class="card-grid" id="yg-${y}"></div>`;
+        container.appendChild(group);
+        const grid = group.querySelector(`#yg-${y}`);
+        items.forEach(ex => grid.appendChild(buildCard(ex)));
+    });
+}
+
+/* ── 타입별 전체보기 ── */
+function showType(type) {
+    // 타입 필터는 검색어로 대신 처리 (엔진/PDF는 _source로 구분)
+    _filterType = type;
+    document.getElementById('featured-section').style.display = 'none';
+    document.getElementById('full-section').style.display = 'block';
+    renderFullList();
+    window.scrollTo({ top: 0, behavior: 'smooth' });
+}
+
+/* ── 홈 리셋 ── */
+function resetView() {
+    document.getElementById('searchInput').value = '';
+    document.getElementById('yearFilter').value  = '';
+    document.getElementById('examTypeFilter').value = '';
+    selectedGrade = '';
+    _filterType   = '';
+    document.querySelectorAll('.gtab').forEach(t => t.classList.remove('active'));
+    document.querySelector('.gtab[data-grade=""]').classList.add('active');
+    onFilterChange();
+}
+
+/* ── 카드 빌더 ── */
+function buildCard(ex) {
+    const isArchive = ex._source === 'archive';
+    const card = document.createElement('div');
+    card.className = 'exam-card';
+
+    let topClass, gradeLabel, titleHTML, badgesHTML, actionsHTML;
+
+    if (isArchive) {
+        topClass   = 'green';
+        gradeLabel = ex.grade || '';
+        titleHTML  = `${ex.school || ''}<br>${ex.exam || ''}`;
+        badgesHTML = `<span class="badge green">PDF기출</span>
+                      ${ex.subject ? `<span class="badge gray">${ex.subject}</span>` : ''}`;
+        actionsHTML = `<div class="action-btn sole" data-action="pdf">PDF 열기</div>`;
+    } else {
+        topClass   = '';
+        gradeLabel = ex.grade || '';
+        
+        // [수정] 학교 명칭 보정: 학년 정보에 근거해 중/고 자동 접미사 추가
+        let displaySchool = ex.school || '';
+        if (gradeLabel.startsWith('중') && !displaySchool.endsWith('중')) displaySchool += '중';
+        else if (gradeLabel.startsWith('고') && !displaySchool.endsWith('고')) displaySchool += '고';
+        
+        const typeText = ex.examType === 'mid' ? '중간' : ex.examType === 'final' ? '기말' : '';
+        titleHTML  = `${displaySchool}<br>${ex.semester ? ex.semester + '학기 ' : ''}${typeText}`;
+        badgesHTML = `<span class="badge blue">엔진기출</span>
+                      ${ex.subject ? `<span class="badge gray">${ex.subject}</span>` : ''}`;
+        actionsHTML = `
+            <div class="action-btn" data-action="exam">시험지</div>
+            <div class="action-btn" data-action="sol">해설지</div>
+            <div class="action-btn" data-action="ans">정답표</div>`;
+    }
+
+    card.innerHTML = `
+        <div class="card-top ${topClass}"></div>
+        <div class="card-body">
+            <div class="card-grade-label">${gradeLabel}</div>
+            <div class="card-main-title">${titleHTML}</div>
+            <div class="badge-row">${badgesHTML}</div>
+        </div>
+        <div class="card-actions">${actionsHTML}</div>`;
+
+    card.querySelectorAll('.action-btn').forEach(btn => {
+        btn.addEventListener('click', e => {
+            e.stopPropagation();
+            openEngine(ex, btn.dataset.action);
+        });
+    });
+
+    return card;
+}
+
+/* ── QPP 모달 ── */
+let _pendingItem   = null;
+let _pendingAction = null;
+
+function openEngine(item, action) {
+    if (item._source === 'archive') {
+        const url = `engine.html?mode=pdf&file=${encodeURIComponent(item.url || item.fileName)}&title=${encodeURIComponent((item.school || '') + ' ' + (item.subject || ''))}`;
+        window.location.href = url;
+        return;
+    }
+    if (action === 'exam') {
+        _pendingItem   = item;
+        _pendingAction = action;
+        document.getElementById('qppModal').classList.add('open');
+        return;
+    }
+    goEngine(item, action, 4);
+}
+
+function confirmQpp(qpp) {
+    closeModal();
+    goEngine(_pendingItem, _pendingAction, qpp);
+}
+
+function closeModal() {
+    document.getElementById('qppModal').classList.remove('open');
+}
+
+function goEngine(item, action, qpp) {
+    const url = `engine.html?mode=${action}&qpp=${qpp}&data=${encodeURIComponent('exams/' + item.file)}&title=${encodeURIComponent((item.school || '') + ' ' + (item.subject || ''))}`;
+    window.location.href = url;
+}
+
+document.getElementById('qppModal').addEventListener('click', function(e) {
+    if (e.target === this) closeModal();
+});
+
+window.onload = init;
+</script>
+</body>
+</html>
